    // 2. Determine the range [min_val, max_val]
    long long min_val = min(n, r);
    long long max_val = max(n, r);

    // 3. Calculate the sum of all primes in the range [min_val, max_val]
    long long sum_of_primes = 0;

    // Since N <= 1000, max_val is also small (at most 1000 if N=1000, reversed is 1)
    // The largest possible reversed number for N <= 1000 is 1000 -> 0001 -> 1, 
    // or 999 -> 999. The range max_val <= 1000.

    for (long long i = min_val; i <= max_val; ++i) {
        if (is_prime(i)) {
            sum_of_primes += i;
